export const config = { runtime: "edge" };

const rateLimitMap = new Map();

function isRateLimited(ip) {
  const now = Date.now();
  const windowMs = 60 * 60 * 1000;
  const maxRequests = 10;
  if (!rateLimitMap.has(ip)) { rateLimitMap.set(ip, { count: 1, start: now }); return false; }
  const entry = rateLimitMap.get(ip);
  if (now - entry.start > windowMs) { rateLimitMap.set(ip, { count: 1, start: now }); return false; }
  if (entry.count >= maxRequests) return true;
  entry.count++;
  return false;
}

const REFERENCE_IMAGE_B64 = "";

export default async function handler(req) {
  if (req.method !== "POST") return new Response("Method not allowed", { status: 405 });

  const origin = req.headers.get("origin") || "";
  const allowedOrigins = ["https://physiqrate.com", "https://www.physiqrate.com"];
  const isAllowed = allowedOrigins.some(o => origin.startsWith(o)) || origin.includes("vercel.app") || origin === "";
  if (!isAllowed) return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 403 });

  const ip = req.headers.get("x-forwarded-for")?.split(",")[0]?.trim() || "unknown";
  if (isRateLimited(ip)) return new Response(JSON.stringify({ error: "Trop de requêtes. Réessaie dans une heure." }), { status: 429 });

  let body;
  try { body = await req.json(); } catch { return new Response(JSON.stringify({ error: "Invalid JSON" }), { status: 400 }); }

  const { imageBase64, gender, age, weight, profilePrompt } = body;
  if (!imageBase64 || !gender) return new Response(JSON.stringify({ error: "Missing fields" }), { status: 400 });
  if (imageBase64.length > 2_800_000) return new Response(JSON.stringify({ error: "Image trop lourde." }), { status: 413 });

  const prompt = `You are an expert body composition analyst.

The FIRST image I am sending you is a REFERENCE CHART showing male body fat percentages at 8%, 10%, 15%, 20%, 25%, 30%, 35%, and 40%. Use this chart as your visual anchor.

The SECOND image is the person to analyze.

Gender: ${gender}
Age: ${age || "unknown"}
Weight: ${weight ? weight + "kg" : "unknown"}
${profilePrompt || ""}

INSTRUCTIONS:
1. Study the reference chart carefully
2. Compare the person's physique to the reference chart
3. Find the closest match
4. Apply lighting corrections:
   - Dark/dim lighting: subtract 2-3%
   - Warm/orange lighting: subtract 1-2%
   - Mirror selfie: subtract 1%
5. Give your final estimate

RULES:
- Be honest and precise
- Do not default to safe middle estimates
- If ab definition is visible → 15% or below for males
- If no ab definition and soft belly → 18% or above for males

Respond ONLY with raw JSON, no markdown:
{
  "bodyfat": <integer>,
  "confidence": <"low"|"medium"|"high">,
  "confidence_reason": "<one sentence>",
  "key_indicators": ["<indicator 1>", "<indicator 2>", "<indicator 3>"],
  "note": "<motivating sentence max 15 words>"
}`;

  const response = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": process.env.ANTHROPIC_API_KEY,
      "anthropic-version": "2023-06-01",
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 1000,
      messages: [{
        role: "user",
        content: [
          { type: "image", source: { type: "base64", media_type: "image/png", data: REFERENCE_IMAGE_B64 } },
          { type: "image", source: { type: "base64", media_type: "image/jpeg", data: imageBase64 } },
          { type: "text", text: prompt }
        ]
      }]
    })
  });

  const data = await response.json();
  if (data.error) return new Response(JSON.stringify({ error: data.error.message }), { status: 500 });

  const text = data.content?.map(b => b.text || "").join("") || "";
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) return new Response(JSON.stringify({ error: "Parse error" }), { status: 500 });

  return new Response(match[0], {
    status: 200,
    headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": origin || "https://physiqrate.com" }
  });
}
